export function authFailedLoginLog(ip: string, username = 'admin') {
  return {
    source: 'auth',
    timestamp: '2026-04-10T18:31:00Z',
    host: 'auth-node-01',
    service: 'auth-service',
    message: `Failed password for ${username} from ${ip} port 55212 ssh2`,
    event: 'login',
    outcome: 'failure',
    reason: 'invalid_password',
    username,
    sourceIp: ip,
    path: '/login',
    userAgent: 'OpenSSH_9.3',
  };
}

